import socketfrom Searcher import screamimport timeHOST = socket.gethostbyname(socket.gethostname())PORT = 8080devices = []server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)server.setblocking(False)server.bind((HOST, PORT))while True:    try:        conn, adr = server.accept()        print("Connected by", adr)        break    except:        scream()        server.listen()        time.sleep(2)while True:    data = conn.recv(10000)    print(data)    input()